// ---------------------------------------------------------------------------
// Apply to .po files (only fills empty msgstr)
// ---------------------------------------------------------------------------

function escapePo(str) {
  return str.replace(/\\/g, '\\\\').replace(/"/g, '\\"').replace(/\n/g, '\\n');
}

const LOCALES = ['fr', 'pt', 'de', 'it', 'zh', 'ja'];

for (const locale of LOCALES) {
  const poPath = path.join(ROOT, `src/locales/${locale}/messages.po`);
  let po = readFileSync(poPath, 'utf-8');
  let filled = 0;

  po = po.replace(
    /^(msgid "((?:[^"\\]|\\.)*)")\s*\n^msgstr ""$/gm,
    (match, msgidLine, msgidRaw) => {
      const key = msgidRaw.replace(/\\"/g, '"').replace(/\\n/g, '\n').replace(/\\\\/g, '\\');
      const entry = T[key];
      if (entry && entry[locale]) {
        filled++;
        return `${msgidLine}\nmsgstr "${escapePo(entry[locale])}"`;
      }
      return match;
    },
  );

  writeFileSync(poPath, po, 'utf-8');
  console.log(`${locale}: filled ${filled}`);
}

console.log('\nDone. Run "npm run i18n:compile" next.');
